import{_ as e,o as r,c as t,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"开通香港综合账户","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/open-hk-account.md","filePath":"zh-CN/account/open-hk-account.md"}'),l={name:"account/open-hk-account.md"};function i(h,a,n,p,c,d){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="开通香港综合账户" tabindex="-1">开通香港综合账户 <a class="header-anchor" href="#开通香港综合账户" aria-label="Permalink to &quot;开通香港综合账户&quot;">​</a></h1><p>香港账户开户资格、中国大陆投资者生活证明要求、三种身份认证方式及账户注销规则。</p><h2 id="账户基本信息" tabindex="-1">账户基本信息 <a class="header-anchor" href="#账户基本信息" aria-label="Permalink to &quot;账户基本信息&quot;">​</a></h2><p>长桥香港综合账户是长桥证券在香港持牌运营的证券账户，账户号码以 H 开头，示例：H12345678。</p><p>开户时效：3-5 个工作日。</p><h2 id="开户资格" tabindex="-1">开户资格 <a class="header-anchor" href="#开户资格" aria-label="Permalink to &quot;开户资格&quot;">​</a></h2><h3 id="年龄要求" tabindex="-1">年龄要求 <a class="header-anchor" href="#年龄要求" aria-label="Permalink to &quot;年龄要求&quot;">​</a></h3><p>申请人需年满 18 周岁。65 岁或以上、或学历为小学程度的客户，开户时需通过电话录音方式进行额外身份确认。</p><h3 id="支持的国家和地区" tabindex="-1">支持的国家和地区 <a class="header-anchor" href="#支持的国家和地区" aria-label="Permalink to &quot;支持的国家和地区&quot;">​</a></h3><p>主要开户人群：香港（含澳门、台湾）、中国大陆。</p><p>其他国家和地区：开户页面下拉列表内有的国家均支持。</p><p>不支持：美国和加拿大证件/信息开户，以及美国和加拿大居民申请开户。</p><p><a href="https://www.fatf-gafi.org/en/countries/fatf.html" target="_blank" rel="noreferrer">支持的国家参考 FATF 官网</a></p><h3 id="中国内地投资者" tabindex="-1">中国内地投资者 <a class="header-anchor" href="#中国内地投资者" aria-label="Permalink to &quot;中国内地投资者&quot;">​</a></h3><p>大陆身份投资者开户需要提供境外生活的证明文件。现时只接受香港及海外地区/国家的身份证件作开户证明，所有工作签、工作证明均不适用。境外（除香港）的驾驶证需要单独人工审核。</p><p>注：非永居香港、非永居澳门身份证明的，可以尝试申请开户。</p><h3 id="香港居民" tabindex="-1">香港居民 <a class="header-anchor" href="#香港居民" aria-label="Permalink to &quot;香港居民&quot;">​</a></h3><p>香港永久性居民身份证可直接申请开户。</p><p>若持有的是香港居民身份证（非永久），需补充提供香港签证身份书或中国内地身份证其一。提供签证书则开户身份为香港居民，提供内地身份证则开户身份为大陆。</p><p>身份证需拍到正面及背面，且须满足 6 个月有效期。</p><h3 id="银行卡要求" tabindex="-1">银行卡要求 <a class="header-anchor" href="#银行卡要求" aria-label="Permalink to &quot;银行卡要求&quot;">​</a></h3><p>开户需要持有港卡。如不持有港卡，需要走第三方见证开户。</p><h2 id="开户认证流程" tabindex="-1">开户认证流程 <a class="header-anchor" href="#开户认证流程" aria-label="Permalink to &quot;开户认证流程&quot;">​</a></h2><p>香港账户提供三种身份认证方式：入金见证、第三方见证、邮寄支票。</p><h3 id="中国大陆用户" tabindex="-1">中国大陆用户 <a class="header-anchor" href="#中国大陆用户" aria-label="Permalink to &quot;中国大陆用户&quot;">​</a></h3><p>通过绑定一张内地银联卡完成身份认证，需填写银联卡卡号和银行开户预留手机号。该银联卡仅用于身份认证，后续不能使用大陆银行卡出入金。</p><p>完成绑定后需进行 CA 验证（Certificate Authorization），通过人脸识别完成。</p><h3 id="中国香港用户-—-入金见证" tabindex="-1">中国香港用户 — 入金见证 <a class="header-anchor" href="#中国香港用户-—-入金见证" aria-label="Permalink to &quot;中国香港用户 — 入金见证&quot;">​</a></h3><p>需一次性入金 10,000 HKD 或 1,500 USD 或以上完成转账验证。</p><p>开户步骤：长桥 App - 资产 - 开户申请 - 立即开户，按页面指引依次完成身份证明上传、个人信息填写、职业信息、资产投资信息、合规信息确认、风险披露，然后在身份认证页面完成转账验证。</p><h3 id="其他地区用户-—-第三方见证" tabindex="-1">其他地区用户 — 第三方见证 <a class="header-anchor" href="#其他地区用户-—-第三方见证" aria-label="Permalink to &quot;其他地区用户 — 第三方见证&quot;">​</a></h3><p>非大陆居民且没有港卡的，需要走第三方见证开户。</p><p>在身份认证页面选择「选择其他开户方式」-「第三方见证」，打印并签署开户资料，连同第三方见证签署的资料安排寄出。寄出后在 APP 内点击「已寄出」提交开户申请。</p><h3 id="其他地区用户-—-邮寄支票" tabindex="-1">其他地区用户 — 邮寄支票 <a class="header-anchor" href="#其他地区用户-—-邮寄支票" aria-label="Permalink to &quot;其他地区用户 — 邮寄支票&quot;">​</a></h3><p>在身份认证页面选择「选择其他开户方式」-「邮寄支票」，可选择上门取件或自行邮寄资料至长桥。开户资料寄出后点击「确认已寄出」，完成手写签名后提交开户申请。长桥收到支票后会完成开户审核。</p><h2 id="休眠账户" tabindex="-1">休眠账户 <a class="header-anchor" href="#休眠账户" aria-label="Permalink to &quot;休眠账户&quot;">​</a></h2><p>账户近 3 年无任何主动操作记录（包括证券交易、新股申购、基金认购、资金存入/提取、股票存入/提取等），且账户资产净值低于等值 100 港币，将被界定为休眠账户。</p><p>休眠账户将暂停交易、出金及股票转出功能。如需重新激活，请联系客服办理。</p><h2 id="修改资料" tabindex="-1">修改资料 <a class="header-anchor" href="#修改资料" aria-label="Permalink to &quot;修改资料&quot;">​</a></h2><p>如需修改姓名、手机号、邮箱等个人信息，请填写信息修改申请表并发送至香港邮箱申请修改。</p><p><a href="https://pub.lbkrs.com/files/202602/unkgiG99RY8AmtaY/___20260206.pdf" target="_blank" rel="noreferrer">信息修改申请表</a></p><p>提交邮箱：service@longbridge.hk</p><p>账户因密码多次错误被冻结，请联系客服协助解冻。</p><h2 id="注销账户" tabindex="-1">注销账户 <a class="header-anchor" href="#注销账户" aria-label="Permalink to &quot;注销账户&quot;">​</a></h2><h3 id="已完成开户" tabindex="-1">已完成开户 <a class="header-anchor" href="#已完成开户" aria-label="Permalink to &quot;已完成开户&quot;">​</a></h3><p>请填写注销申请表并发送邮件至香港官方邮箱申请注销。</p><p><a href="https://pub.lbkrs.com/files/202602/LS5FyJKJf5ZmQAVT/___20260225.pdf" target="_blank" rel="noreferrer">注销申请表</a></p><p>提交邮箱：service@longbridge.hk</p><blockquote><p>预计处理时间：7 个工作日内。</p></blockquote><p>注意事项：</p><ul><li>注销账户可以放弃账户内现金，但不可以放弃账户内的股票</li><li>可选择将证券账户内的港股以实物方式提取，或转出至其他证券公司</li><li>账号注销后所有信息将被清空且不可恢复</li><li>注销前需结清所有资产、无待结算交易</li><li>需解除所有第三方绑定（如 eDDA、银证转账等）</li><li>如有新股认购中签权益将视为自动放弃</li><li>注销后 90 天内不可使用同一证件重新注册</li></ul><h3 id="未完成开户" tabindex="-1">未完成开户 <a class="header-anchor" href="#未完成开户" aria-label="Permalink to &quot;未完成开户&quot;">​</a></h3><p>开户未完成的账户，请联系客服协助处理注销。</p>',53)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
